import React, { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import { ArrowLeft, Shield, Calendar, AlertCircle, UserMinus, UserPlus, Search } from "lucide-react";
import CaseTabs from "./CaseTabs.js";
import TimelineTab from "./TimelineTab.js";
import MembersTab from "./MembersTab.js";
import EvidenceTab from "./EvidenceTab.js";
import '../../components/Components.css';
import api from "../../api.js";

const PRIORITY_MAP = { 3: { label: "High", color: "#f87171", bg: "rgba(239,68,68,0.1)" }, 2: { label: "Medium", color: "#fbbf24", bg: "rgba(245,158,11,0.1)" }, 1: { label: "Low", color: "#34d399", bg: "rgba(16,185,129,0.1)" } };
const STATUS_MAP = { Open: { color: "#34d399", bg: "rgba(52,211,153,0.1)" }, Close: { color: "#f87171", bg: "rgba(239,68,68,0.1)" }, Archived: { color: "#94a3b8", bg: "rgba(148,163,184,0.1)" } };

export default function CaseDetails() {
  const { caseId } = useParams();
  const navigate = useNavigate();
  const user = JSON.parse(localStorage.getItem("user"));
  const isAdmin = user?.role_id === 1;

  const [caseData, setCaseData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [statusUpdating, setStatusUpdating] = useState(false);

  const fetchCase = async () => {
    try {
      setLoading(true);
      const res = await api.get(`/case/${caseId}`);
      setCaseData(res.data);
    } catch (err) {
      if (err.response?.status === 403) {
        setError("You do not have access to this case.");
      } else {
        setError("Case not found.");
      }
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchCase(); }, [caseId]);

  const handleStatusChange = async (newStatus) => {
    if (!isAdmin) return;
    setStatusUpdating(true);
    try {
      await api.patch(`/case/${caseId}/status`, { status: newStatus });
      setCaseData((prev) => ({ ...prev, status: newStatus }));
    } catch (err) {
      alert("Failed to update status");
    } finally {
      setStatusUpdating(false);
    }
  };

  const handleDeleteCase = async () => {
    if (!window.confirm(`Delete case "${caseData?.title}"? This cannot be undone.`)) return;
    try {
      await api.delete(`/case/${caseId}`);
      navigate("/cases");
    } catch (err) {
      alert("Failed to delete case");
    }
  };

  const priority = PRIORITY_MAP[caseData?.priority] || PRIORITY_MAP[1];
  const statusStyle = STATUS_MAP[caseData?.status] || STATUS_MAP["Open"];

  const formatDate = (d) => d ? new Date(d).toLocaleDateString("en-GB", { day: "2-digit", month: "short", year: "numeric" }) : "—";

  const tabs = caseData ? [
    { label: "Timeline", content: <TimelineTab caseId={caseId} caseData={caseData} /> },
    { label: "Members", content: <MembersTab members={caseData?.members || []} leadInvestigators={caseData?.leadInvestigators || []} memberDetails={caseData?.memberDetails || []} caseId={caseId} isAdmin={isAdmin} onRefresh={fetchCase} /> },
    { label: "Evidence", content: <EvidenceTab caseId={caseId} userRole={user?.role_id} /> },
  ] : [];

  if (loading) return (
    <div className="detailsPage" style={{ display: "flex", alignItems: "center", justifyContent: "center", minHeight: "50vh" }}>
      <div style={{ textAlign: "center", color: "#475569" }}>
        <div className="miniSpinner" style={{ margin: "0 auto 1rem", width: 32, height: 32 }} />
        <p>Loading case details...</p>
      </div>
    </div>
  );

  if (error) return (
    <div className="detailsPage">
      <button onClick={() => navigate(-1)} className="backBtn"><ArrowLeft size={18} /> Back</button>
      <div className="detailsGlassCard" style={{ textAlign: "center", padding: "3rem" }}>
        <AlertCircle size={48} color="#f87171" style={{ marginBottom: "1rem" }} />
        <p style={{ color: "#f87171", fontSize: "1.125rem" }}>{error}</p>
      </div>
    </div>
  );

  return (
    <div className="detailsPage">
      <button onClick={() => navigate(-1)} className="backBtn"><ArrowLeft size={18} /> Back to Cases</button>

      <div className="detailsGlassCard">
        {/* Header */}
        <header className="detailsHeader" style={{ borderBottom: "1px solid rgba(255,255,255,0.06)", paddingBottom: "1.5rem", marginBottom: "1.5rem" }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", gap: "1rem" }}>
            <div>
              <div style={{ display: "flex", alignItems: "center", gap: "0.75rem", marginBottom: "0.5rem" }}>
                <span style={{ fontFamily: "monospace", fontSize: "0.8rem", color: "#818cf8", background: "rgba(129,140,248,0.1)", padding: "3px 10px", borderRadius: 6 }}>
                  Case #{caseId}
                </span>
                <span style={{ background: statusStyle.bg, color: statusStyle.color, padding: "3px 10px", borderRadius: 6, fontSize: "0.75rem", fontWeight: 700 }}>
                  {caseData?.status}
                </span>
                <span style={{ background: priority.bg, color: priority.color, padding: "3px 10px", borderRadius: 6, fontSize: "0.75rem", fontWeight: 700 }}>
                  {priority.label} Priority
                </span>
              </div>
              <h1 style={{ fontSize: "1.75rem", fontWeight: 700, color: "#fff", margin: 0 }}>{caseData?.title}</h1>
              {caseData?.description && <p style={{ color: "#64748b", marginTop: "0.5rem", fontSize: "0.9rem" }}>{caseData.description}</p>}
            </div>

            {/* Admin actions */}
            {isAdmin && (
              <div style={{ display: "flex", gap: "0.75rem", flexShrink: 0 }}>
                <select
                  value={caseData?.status}
                  onChange={(e) => handleStatusChange(e.target.value)}
                  disabled={statusUpdating}
                  style={{ background: "#1e293b", border: "1px solid rgba(255,255,255,0.1)", color: "#fff", padding: "0.5rem 0.75rem", borderRadius: 8, fontSize: "0.85rem", cursor: "pointer" }}
                >
                  <option value="Open">Set: Open</option>
                  <option value="Close">Set: Close</option>
                  <option value="Archived">Set: Archived</option>
                </select>
                <button
                  onClick={handleDeleteCase}
                  style={{ background: "rgba(239,68,68,0.1)", border: "1px solid rgba(239,68,68,0.2)", color: "#f87171", padding: "0.5rem 1rem", borderRadius: 8, fontSize: "0.85rem", cursor: "pointer", fontWeight: 600 }}
                >
                  Delete Case
                </button>
              </div>
            )}
          </div>
        </header>

        {/* Info Grid */}
        <div className="detailsInfoGrid">
          <div className="infoTile">
            <h4>Lead Investigators</h4>
            <p style={{ color: "#34d399", fontWeight: 500 }}>
              {caseData?.leadInvestigators?.length ? caseData.leadInvestigators.join(", ") : "Unassigned"}
            </p>
          </div>
          <div className="infoTile">
            <h4>Total Members</h4>
            <p style={{ color: "#818cf8", fontWeight: 600, fontSize: "1.25rem" }}>{caseData?.members?.length || 0}</p>
          </div>
          <div className="infoTile">
            <h4><Calendar size={12} style={{ marginRight: 4 }} />Start Date</h4>
            <p>{formatDate(caseData?.start_date)}</p>
          </div>
          <div className="infoTile">
            <h4>End Date</h4>
            <p>{caseData?.end_date ? formatDate(caseData.end_date) : <span style={{ color: "#475569" }}>Ongoing</span>}</p>
          </div>
        </div>

        {/* Tabs */}
        <CaseTabs tabs={tabs} />
      </div>
    </div>
  );
}
